const queries = $input.first().json.output.searchQueries.map((s) => ({
  query: s,
}));

return queries;

const searchResults = $input.first().json.organic || [];
const excludePatterns = [
  /\/blog\//i,
  /\/article\//i,
  /\/post\//i,
  /\/news\//i,
  /\/articles\//i,
  /\/posts\//i,
  /\/magazine\//i,
  /medium\.com/i,
  /wordpress\.com/i,
  /blogspot\.com/i,
  /tumblr\.com/i,
  /reddit\.com/i,
  /quora\.com/i,
  /stackoverflow\.com/i,
  /github\.com/i,
  /wikipedia\.org/i,
  /\/forum\//i,
  /\/discussion\//i,
  /\/guide\//i,
  /\/how-to\//i,
  /\/tutorial\//i,
  /\.pdf$/i,
  /linkedin\.com\/posts/i,
  /twitter\.com/i,
  /facebook\.com/i,
  /fintechmagazine\.com/i,
  /eternitech\.com/i,
  /v-comply\.com\/blog/i
];
const articleIndicators = [
  /^top\s+\d+/i,
  /\stop\s+\d+/i,
  /^\d+\s+(best|top)/i,
  /list\s+of/i,
  /^the\s+\d+/i,
  /\s+in\s+\d{4}$/i,
  /\s+companies\s+in\s+the/i,
  /\s+software\s+for\s+/i,
  /\s+solutions\s+for\s+/i,
  /\s+help\s+firms/i,
  /\s+software\s+helps/i,
  /\s+software\s+is\s+key/i
];
const companyIndicators = [
  /^https?:\/\/[^\/]+\/?$/i,
  /\/about/i,
  /\/company/i,
  /\/contact/i,
  /\/products/i,
  /\/solutions/i,
  /\/services/i,
  /\/platform/i,
  /\/software/i,
  /\/industries/i,
  /\/en-us/i,
  /\/en\//i
];

const companies = searchResults
  .map(result => {
    const url = result.link || '';
    const title = result.title || '';
    const snippet = result.snippet || '';

    if (excludePatterns.some(pattern => pattern.test(url))) {
      return null;
    }

    if (articleIndicators.some(pattern => pattern.test(title) || pattern.test(snippet))) {
      return null;
    }

    if (/this software|this platform|helps firms|software is key|software helps|firms can|companies can/i.test(snippet)) {
      return null;
    }

    let companyName = "";
    let splitter = url.split("/")[2].split(".");

    if (splitter.includes("www")) {
      companyName = splitter[1];
    } else {
      companyName = splitter[0];
    }

    let score = 0;

    if (/^https?:\/\/[^\/]+\/?$/i.test(url)) {
      score += 10;
    }

    companyIndicators.forEach(pattern => {
      if (pattern.test(url)) score += 2;
    });

    if (!articleIndicators.some(p => p.test(title)) && title.length < 60) {
      score += 3;
    }

    if (/platform|software|solution|service|product/i.test(snippet) && 
        !/this software|this platform|helps firms/i.test(snippet)) {
      score += 2;
    }

    return {
      name: companyName || url,
      website: url,
      snippet: snippet,
      position: result.position,
      score: score
    };
  })
  .filter(company => company !== null && company.website && company.website.match(/^https?:\/\//))
  .sort((a, b) => {
    if (b.score !== a.score) return b.score - a.score;
    return a.position - b.position;
  })
  .slice(0, 30);

const uniqueCompanies = [];
const seenDomains = new Set();

for (const company of companies) {
  const domain = company.website.replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '');
  if (!seenDomains.has(domain)) {
    seenDomains.add(domain);
    uniqueCompanies.push({
      ...company,
      domain: domain
    });
  }
}

return uniqueCompanies.slice(0, 20);

const items = $input.all();
const companyNamesSet = new Set();

for (const item of items) {
  const companyName = item.json["Company Name"];
  if (companyName) {
    companyNamesSet.add(companyName);
  }
}

const companyNamesArray = Array.from(companyNamesSet);
return {
  companies: companyNamesArray,
};

const array1 = $("Parse Companies").all(0).map(item => item.json);
const array2 = $input.all(1)[0].json.companies;

const blacklist = new Set(
  array2.map(name => name.toLowerCase().trim())
);

const filtered = array1.filter(item =>
  !blacklist.has(item.name.toLowerCase().trim())
);

return filtered.map(item => ({ json: item }));

const items = $input.all();
const structureCompanyInfo = $('Loop Over Companies').all()[0] || {};

return items.map((i) => ({
  email: i.json.value,
  title: i.json.position,
  linkedin: i.json.linkedin,
  companyDomain: structureCompanyInfo.json.domain,
  name: `${i.json.first_name} ${i.json.last_name}`,
  companyName: structureCompanyInfo.json.companyName,
})).filter((i) => i.name !== "null null");

